#requires -Version 5.1
[CmdletBinding()]
param(
  [string]$ProjectPath = 'C:\Users\hramirez\Documents\PROYECTOS-H\ZelogiG'
)
Set-StrictMode -Version Latest
$ErrorActionPreference = 'Stop'

function Write-Encoded([string]$RelativePath, [string]$Payload) {
  $target = Join-Path $ProjectPath $RelativePath
  $parent = Split-Path -Parent $target
  if (-not (Test-Path -LiteralPath $parent)) { New-Item -ItemType Directory -Path $parent -Force | Out-Null }
  if (Test-Path -LiteralPath $target) {
    $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
    Copy-Item -LiteralPath $target -Destination "$target.backup-$stamp" -Force
  }
  [IO.File]::WriteAllBytes($target, [Convert]::FromBase64String($Payload))
  Write-Host "ACTUALIZADO: $RelativePath" -ForegroundColor Green
}

Write-Host 'ZelogiG - Sistemas de experiencia móvil' -ForegroundColor Cyan

Write-Encoded 'docs\35_animation_system.md' ''
Write-Encoded 'docs\36_audio_and_haptics.md' ''
Write-Encoded 'docs\37_mobile_experience.md' ''
Write-Encoded 'docs\38_game_event_contract.md' ''
Write-Encoded 'docs\39_experience_stack_decisions.md' ''
Write-Encoded 'docs\40_future_experience_backlog.md' ''
Write-Encoded 'docs\diagramas\sistema-experiencia.md' ''
Write-Encoded 'docs\decisions\D-009-experience-foundation.md' ''

$logPath = Join-Path $ProjectPath 'docs\bitacora.md'
if (-not (Test-Path -LiteralPath $logPath)) { throw "No existe $logPath" }
$content = [IO.File]::ReadAllText($logPath, [Text.Encoding]::UTF8)
$title = 'Sistemas de animación, audio, tacto y experiencia móvil'
if ($content -notmatch [regex]::Escape($title)) {
  $entry = @"
## $(Get-Date -Format 'yyyy-MM-dd') - $title

- **Estado:** COMPLETO
- **Que se hizo:** Se definieron el sistema de animación, audio, respuesta táctil, experiencia Mobile First, contrato de eventos neutrales, decisiones de stack y pendientes futuros. Se agregó el diagrama del sistema de experiencia y la decisión D-009.
- **Decision + porque:** [Seguro] El MVP usará CSS, SVG y APIs nativas detrás de adaptadores. No se agregan bibliotecas hasta demostrar una necesidad que las justifique.
- **Contexto:** Lectura directa de la documentación y decisiones aprobadas por el propietario; graphify no disponible y no generado.
- **Validacion:** Documentación y diagrama generados con PowerShell 5.1. No se modificó código del motor ni se ejecutó NPM.
- **Costo:** No disponible desde este entorno; no se inventan tokens ni USD.
- **Siguiente paso:** Publicar cambios en GitHub y, al disponer de Node.js, revisar el contrato de eventos contra el motor antes de implementarlo.
- **Bloqueos / pendientes de humano:** Node.js sigue bloqueado en el equipo corporativo. GitHub debe autenticarse con la cuenta propietaria.

### Decisiones deliberadas, no deshacer

- Mobile First real, no adaptación tardía.
- CSS y SVG como base del MVP.
- Eventos neutrales entre motor y efectos.
- Audio y vibración opcionales.
- Ninguna dependencia nueva queda autorizada automáticamente.

---

"@
  $marker = '---'
  $index = $content.IndexOf($marker)
  if ($index -lt 0) { throw 'La bitácora no contiene el separador esperado.' }
  $insertAt = $index + $marker.Length
  $updated = $content.Substring(0,$insertAt) + "`r`n`r`n" + $entry + $content.Substring($insertAt).TrimStart("`r","`n")
  [IO.File]::WriteAllText($logPath, $updated, (New-Object Text.UTF8Encoding($false)))
  Write-Host 'ACTUALIZADO: docs\bitacora.md' -ForegroundColor Green
}

$audit = Join-Path $ProjectPath 'scripts\Audit-ZelogiG.ps1'
if (Test-Path -LiteralPath $audit) { & $audit }

Write-Host ''
Write-Host 'Documentación de experiencia completada.' -ForegroundColor Cyan
